// AI Agent обработал 1 файл
// Считаем сколько файлов найдено в "Вытаскиваем файл с content" и присваиваем следующий номер

// Берём AI output
let aiOutput = 'No content';
try {
  const aiData = $('AI Agent4').first().json;
  aiOutput = aiData.output || aiData.text || aiData.content || 'No content';
} catch(e) {
  console.log('Cannot get AI output:', e.message);
}

// Считаем сколько файлов найдено
let foundFilesCount = 0;
try {
  foundFilesCount = $('Вытаскиваем файл с content1').all().length;
} catch(e) {
  console.log('Cannot count files:', e.message);
}

// Номер = найденные файлы + 1
const itemNumber = foundFilesCount + 1;

console.log('Found files:', foundFilesCount);
console.log('New file number:', itemNumber);
console.log('AI Output preview:', aiOutput.substring(0, 100));

// Формируем файл: prompt_content_5.md
const fileName = `prompt_content_${itemNumber}.md`;

const mdContent = `# AI Response\n\n${aiOutput}`;
const buffer = Buffer.from(mdContent, 'utf8');

return [{
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: fileName,
    }
  },
  json: {
    source: 'AI Agent',
    format: 'markdown',
    fileName: fileName,
    itemNumber: itemNumber,
    foundFilesCount: foundFilesCount,
  }
}];

const items = $input.all();

for (const item of items) {
  const attachments = item.json?.fields?.attachment || [];

  for (const att of attachments) {
    let fileName = att.fileName || att.filename || att.name || '';

    // Если имени нет, берем из URL и декодируем
    if (!fileName && att.content) {
      const clean = att.content.split('?')[0].split('#')[0];
      fileName = decodeURIComponent(clean.split('/').pop());
    }

    if (!fileName) continue;

    // Декодируем на всякий случай
    fileName = decodeURIComponent(fileName);

    // Извлекаем только имя файла (без пути)
    const baseName = fileName.split('/').pop().split('\\').pop();
    const lowerName = baseName.toLowerCase();

    // Проверка readme.md:
    // ✅ Readme.md
    // ✅ Readme (1).md, Readme (2).md и т.д.
    // ❌ Readme_670b72259a3cd.md (с underscore)
    const isReadme = (
      lowerName === 'readme.md' || 
      lowerName.match(/^readme\s*\(\d+\)\.md$/)
    ) && !baseName.includes('_');

    if (isReadme) {
      // Извлекаем ID из URL
      let attachmentId = null;

      // Вариант 1: из content URL (.../attachment/206556/Readme...)
      if (att.content) {
        const match = att.content.match(/\/attachment\/(\d+)\//);
        if (match) attachmentId = match[1];
      }

      // Вариант 2: из self URL (.../api/2/attachment/206556)
      if (!attachmentId && att.self) {
        const match = att.self.match(/\/attachment\/(\d+)$/);
        if (match) attachmentId = match[1];
      }

      // Вариант 3: прямое поле id
      if (!attachmentId && att.id) {
        attachmentId = att.id.toString();
      }

      return [
        {
          json: {
            attachmentId: attachmentId,
            fileName: baseName
          }
        }
      ];
    }
  }
}

// Если не нашли
return [
  {
    json: {
      attachmentId: null,
      error: 'Readme.md not found'
    }
  }
];

const items = $input.all();
let foundReadme = null;
let fallbackReadme = null;

for (const item of items) {
  const attachments = item.json?.fields?.attachment || [];

  for (const att of attachments) {
    let fileName = att.fileName || att.filename || att.name || '';
    if (!fileName && att.content) {
      const clean = att.content.split('?')[0].split('#')[0];
      fileName = clean.split('/').pop();
    }
    if (!fileName) continue;

    fileName = decodeURIComponent(fileName);
    const baseName = fileName.split('/').pop().split('\\').pop();
    const lowerName = baseName.toLowerCase();

    const getAttachmentId = (attachment) => {
      let id = null;
      if (attachment.content) {
        const match = attachment.content.match(/\/attachment\/(\d+)\//);
        if (match) id = match[1];
      }
      if (!id && attachment.self) {
        const match = attachment.self.match(/\/attachment\/(\d+)$/);
        if (match) id = match[1];
      }
      if (!id && attachment.id) id = attachment.id.toString();
      return id;
    };

    if (lowerName === 'readme.md' && !baseName.includes('_') && !baseName.match(/readme\s*\(\d+\)\.md/i)) {
      foundReadme = { attachmentId: getAttachmentId(att), fileName: baseName };
      break;
    }

    if (lowerName === 'readme (1).md' && !fallbackReadme) {
      fallbackReadme = { attachmentId: getAttachmentId(att), fileName: baseName };
    }
  }
  if (foundReadme) break;
}

if (foundReadme) return [{ json: foundReadme }];
if (fallbackReadme) return [{ json: fallbackReadme }];
return [{ json: { attachmentId: null, error: 'Readme.md not found' } }];

let readmeContent = null;
try {
  const extractNode = $('Extract Main Readme').first();
  readmeContent = extractNode.json?.data || null;
} catch (e) {
  console.log('Extract Main Readme not found');
}

const contentNames = {};
if (readmeContent) {
  const lines = readmeContent.split('\n');
  for (const line of lines) {
    // Исправлено: буквенно-цифровой ID (5+ символов) вместо только hex (10+)
    const match = line.match(/^\s*`?([a-zA-Z0-9]{5,})`?\s*[-–—]\s*(.+)$/i);
    if (match) {
      contentNames[match[1].toLowerCase()] = match[2].trim();
    }
  }
}

const getAttachmentId = (att) => {
  if (att.content) {
    const m = att.content.match(/\/attachment\/(\d+)\//);
    if (m) return m[1];
  }
  if (att.self) {
    const m = att.self.match(/\/attachment\/(\d+)$/);
    if (m) return m[1];
  }
  return att.id?.toString() || null;
};

const fileMap = {};
try {
  const issueItems = $('Get an issue17').all();
  for (const item of issueItems) {
    const attachments = item.json?.fields?.attachment || [];
    for (const att of attachments) {
      // Проверяем все варианты имени файла (fileName, filename, name)
      let fileName = att.fileName || att.filename || att.name || att.Filename || att.FileName || '';
      if (!fileName && att.content) {
        fileName = decodeURIComponent(att.content.split('?')[0].split('/').pop() || '');
      }
      if (!fileName) continue;

      fileName = decodeURIComponent(fileName);

      // Приводим к нижнему регистру для поиска
      const lowerName = fileName.toLowerCase();

      // Ищем readme_ или content_ независимо от регистра
      const hasReadme = lowerName.includes('readme_');
      const hasContent = lowerName.includes('content_');

      if (!hasReadme && !hasContent) continue;

      // Исправлено: буквенно-цифровой ID (5+ символов) вместо только hex (10+)
      const match = fileName.match(/[_]([a-zA-Z0-9]{5,})/i);
      const fileId = match ? match[1].toLowerCase() : null;
      if (!fileId) continue;

      if (!fileMap[fileId]) {
        fileMap[fileId] = { 
          id: fileId, 
          readme: null, readmeAttId: null,
          content: null, contentAttId: null,
          contentName: contentNames[fileId] || 'Unknown'
        };
      }

      if (hasReadme) {
        fileMap[fileId].readme = fileName;
        fileMap[fileId].readmeAttId = getAttachmentId(att);
      } else if (hasContent) {
        fileMap[fileId].content = fileName;
        fileMap[fileId].contentAttId = getAttachmentId(att);
      }
    }
  }
} catch (e) {
  console.log('Error:', e.message);
}

const results = Object.values(fileMap).map((pair, index) => ({ json: { ...pair, loopIndex: index + 1 } }));
return results.length > 0 ? results : [{ json: { error: 'No readme_ID/content_ID files found' } }];

// COMBINE DATA - получаем metadata из Loop Over Items
const items = $input.all();

// Получаем metadata из Loop - ищем узел по разным именам
let loopItem = null;
const loopNames = ['Loop Over Items', 'Loop Over Items1', 'Loop'];
for (const name of loopNames) {
  try {
    loopItem = $(name).first().json;
    if (loopItem && loopItem.id) break;
  } catch(e) {}
}

// Fallback - берём из items если есть
if (!loopItem || !loopItem.id) {
  loopItem = { id: '', contentName: '', loopIndex: 1, readme: '', content: '' };
  for (const item of items) {
    if (item.json?.id) loopItem.id = item.json.id;
    if (item.json?.contentName) loopItem.contentName = item.json.contentName;
    if (item.json?.loopIndex) loopItem.loopIndex = item.json.loopIndex;
    if (item.json?.readme) loopItem.readme = item.json.readme;
    if (item.json?.content) loopItem.content = item.json.content;
  }
}

let readmeText = '';
let contentJson = '';

for (const item of items) {
  const text = item.json?.data || '';
  if (!text) continue;

  const trimmed = text.trim();

  if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
    contentJson = text;
  } else {
    readmeText = text;
  }
}

return [{
  json: {
    id: loopItem.id || '',
    contentName: loopItem.contentName || '',
    loopIndex: loopItem.loopIndex || 1,
    readme: loopItem.readme || '',
    content: loopItem.content || '',
    readmeText: readmeText || 'README not extracted',
    contentJson: contentJson || 'Content JSON not extracted'
  }
}];

